import{_ as e,o as a,c as i,ag as n}from"./chunks/framework.CbQjVMS6.js";const k=JSON.parse('{"title":"Strip Comments & Whitespace","description":"","frontmatter":{},"headers":[],"relativePath":"features/strip-comments.md","filePath":"features/strip-comments.md","lastUpdated":1774323326000}'),t={name:"features/strip-comments.md"};function l(o,s,p,c,r,h){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="strip-comments-whitespace" tabindex="-1">Strip Comments &amp; Whitespace <a class="header-anchor" href="#strip-comments-whitespace" aria-label="Permalink to &quot;Strip Comments &amp; Whitespace&quot;">​</a></h1><p>When I first started using TI Basic, two of my biggest frustrations were:</p><ul><li>Not being able to indent sections of code</li><li>Not being able to easily document my code with comments<br> (or if I did, it would increase the file size!)</li></ul><p>So I fixed it. With Powerpack, you can now use unlimited spaces, tabs and newlines, and comment your code as extensively as you like, and these will all be removed during compilation to keep your final program size small.</p><h2 id="indent-code-and-blank-lines" tabindex="-1">Indent code and blank lines <a class="header-anchor" href="#indent-code-and-blank-lines" aria-label="Permalink to &quot;Indent code and blank lines&quot;">​</a></h2><p>Here’s an example of what you can do in Powerpack:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Say hello</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">If A=1:Then</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A+1→A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Disp &quot;Hello World&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">End</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp &quot;Finished&quot;</span></span></code></pre></div><p>When running <code>Powerpack EXAMPLE.8xp</code>, it will remove the comments and unnecessary whitespace, and produce something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">If A=1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Then</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">A+1→A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp &quot;Hello World</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">End</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp &quot;Finished</span></span></code></pre></div><p>Powerpack removes all blank lines and whitespace at the <em>start</em> of a line.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Be careful you don’t leave spaces/tabs at the <em>end</em> of a line, as this will produce an error on your calculator.</p></div><h2 id="comments" tabindex="-1">Comments <a class="header-anchor" href="#comments" aria-label="Permalink to &quot;Comments&quot;">​</a></h2><p>There are three types of comments you can use with Powerpack, and all three will be removed from the compiled program.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Here is a comment</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&quot;Here is another comment</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/*</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">And here is a multi-line comment</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">*/</span></span></code></pre></div><p>This allows you to use comments generously and not be afraid of increasing file size. Comments are invaluable when disabling certain sections of code, or when coming back to your program at later time and being able to determine why you coded something the way you did!</p><p>Strings that are used in a function, stored into a variable, or having a closing <code>&quot;</code> double-quote will remain in the compiled program and <em>not</em> be stripped. See below.</p><h2 id="edge-case-placing-strings-into-ans" tabindex="-1">Edge case: placing strings into <code>Ans</code> <a class="header-anchor" href="#edge-case-placing-strings-into-ans" aria-label="Permalink to &quot;Edge case: placing strings into \`Ans\`&quot;">​</a></h2><p>There might be certain times that you want to place a string into Ans or another variable and not have it stripped out. In such a case, be sure to put a closing double-quote character, or use the <code>→STO</code> character, like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&quot;Line 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">			  // ❌ This line will be removed by Powerpack</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Line 2&quot;		  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Will be kept</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Line 3→Str1	  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Will be kept</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Line 4&quot;→Str1	  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Will be kept</span></span></code></pre></div><p>The above code will be compiled into this:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Line 2</span></span>
<span class="line"><span>&quot;Line 3→Str1</span></span>
<span class="line"><span>&quot;Line 4→Str1</span></span></code></pre></div><p>In summary: if a line of code contains a <code>&quot;</code> closing quote or the <code>→STO</code> character, the line will not be stripped during compilation.</p><p>The <a href="./ti-basic-optimization">optimization step</a> that occurs later will remove any unnecessary closing quotes or brackets.</p>`,23)])])}const m=e(t,[["render",l]]);export{k as __pageData,m as default};
